from datetime import UTC, datetimefrom apscheduler.schedulers.background import BackgroundSchedulerfrom app.config import get_settingsfrom app.health import HealthCheckResult, run_health_checksfrom app.memory.repository import delete_timer, list_due_timersfrom app.proactive.background_tick import check_presence_timeouts, run_proactive_background_tickfrom app.runtime.activity import activityfrom app.runtime.status_copy import HEALTH_ISSUE_DETECTED_TITLEfrom app.voice.service import GladosVoiceService, VoiceUnavailableErrorscheduler = BackgroundScheduler(daemon=True)_LAST_HEALTH_STATUS: dict[str, bool] = {}def check_due_timers() -> None:    """    Check due timers.    Returns:        None.    """    timers = list_due_timers(datetime.now(UTC))    for timer in timers:        if timer.id is None:            continue        title, detail = _format_due_timer(timer.label, timer.created_at, timer.due_at)        activity.log(title=title, detail=detail, source="scheduler.timers")        _announce_timer_completion(detail)        delete_timer(timer.id)def _format_due_timer(label: str, created_at: datetime, due_at: datetime) -> tuple[str, str]:    """    Format due timer.    Args:        label: Timer label.        created_at: Timestamp when the record was created.        due_at: Timer due timestamp.    Returns:        Tuple containing the requested values.    """    display_label = label.strip() or "Timer"    duration_seconds = max(1, int((due_at - created_at).total_seconds()))    label_suffix = "" if display_label == "Timer" else f" for {display_label}"    return (        "Timer complete.",        f"Your {_humanize_duration(duration_seconds)} timer{label_suffix} is complete.",    )def _humanize_duration(duration_seconds: int) -> str:    """    Humanize duration.    Args:        duration_seconds: Duration value in seconds.    Returns:        Generated or formatted string value.    """    if duration_seconds % 60 == 0:        minutes = duration_seconds // 60        if minutes == 1:            return "1 minute"        return f"{minutes} minutes"    if duration_seconds == 1:        return "1 second"    return f"{duration_seconds} seconds"def _announce_timer_completion(message: str) -> None:    """    Announce timer completion.    Args:        message: User message or prompt text.    Returns:        None.    """    try:        GladosVoiceService().announce(message)    except VoiceUnavailableError:        returndef check_system_health() -> list[HealthCheckResult]:    """    Check system health.    Returns:        List of matching records or values.    """    results = run_health_checks()    failing = [result for result in results if not result.ok]    if not failing:        for result in results:            previous = _LAST_HEALTH_STATUS.get(result.name)            _LAST_HEALTH_STATUS[result.name] = True            if previous is False:                activity.log(                    title="Health check recovered.",                    detail=f"{result.name}: {result.detail}",                    source="scheduler.health",                )        return results    for result in results:        previous = _LAST_HEALTH_STATUS.get(result.name)        _LAST_HEALTH_STATUS[result.name] = result.ok        if result.ok:            continue        activity.error(            title=HEALTH_ISSUE_DETECTED_TITLE,            detail=f"{result.name}: {result.detail}",            source="scheduler.health",        )        if previous is not False:            _announce_health_issue(result)    return resultsdef _announce_health_issue(result: HealthCheckResult) -> None:    """    Announce health issue.    Args:        result: Result value.    Returns:        None.    """    message = f"I detected a problem with {result.name}. {result.detail}"    try:        GladosVoiceService().announce(message)    except VoiceUnavailableError:        returndef register_jobs() -> None:    """    Register jobs.    Returns:        None.    """    settings = get_settings()    scheduler.add_job(        check_due_timers,        "interval",        seconds=settings.timer_poll_interval_seconds,        id="check_due_timers",        replace_existing=True,        max_instances=1,    )    scheduler.add_job(        check_system_health,        "interval",        seconds=settings.health_check_interval_seconds,        id="check_system_health",        replace_existing=True,        max_instances=1,    )    scheduler.add_job(        run_proactive_background_tick,        "interval",        seconds=settings.proactive_background_interval_seconds,        id="run_proactive_background_tick",        replace_existing=True,        max_instances=1,    )    scheduler.add_job(        check_presence_timeouts,        "interval",        seconds=settings.presence_check_poll_interval_seconds,        id="check_presence_timeouts",        replace_existing=True,        max_instances=1,    )